StringLiteralEqualityCheck.checker_dsl:
EXISTS (`EO`) {
  AND {
    (`EO is of type EQUAL (==) or NOT_EQUAL (!=)`),
    EXISTS (`N`) {
      AND {
        (`N is EO or is reachable from EO by repeatedly taking the first direct child of type PLUS`),
        (`N has a direct child of type STRING_LITERAL or TEXT_BLOCK_LITERAL_BEGIN`)
      }
    }
  }
}

FallThroughCheck.checker_dsl:
EXISTS (`case group CG`) {
  AND {
    (`CG has a child of type SLIST`),
    NOT { (`the SLIST child of CG is terminated (its last statement is a break, return, continue, throw, or a method call that never returns normally)`) },
    OR {
      (`CG is not the last case group in its parent switch statement (its next sibling is not a CASE_GROUP)`)
    },
    NOT {
      EXISTS (`node N`) {
        AND {
          OR {
            AND {
              (`the next sibling of CG is a CASE_GROUP`),
              (`N is the first child of that next CASE_GROUP`)
            },
            AND {
              (`the next sibling of CG is not a CASE_GROUP`),
              (`N is CG`)
            }
          },
          EXISTS (`node M`) {
            AND {
              (`M is the next non-comment AST node after N`),
              (`M is not null`),
              EXISTS (`sibling S`) {
                AND {
                  (`S is a sibling of M`),
                  (`S is located before M in the sibling order`),
                  (`the line number of S equals the line number of the immediate previous sibling of M`),
                  EXISTS (`child C`) {
                    AND {
                      (`C is the first child of S`),
                      (`C is not null`),
                      (`the text of C matches the configured relief pattern (default: variations of 'fall through')`)
                    }
                  }
                }
              }
            }
          }
        }
      }
    }
  }
}

MissingSwitchDefaultCheck.checker_dsl:
EXISTS (`switch SW`) {
  AND {
    NOT {
      EXISTS (`case CG1`) {
        (`CG1 contains a child token of type LITERAL_DEFAULT`)
      }
    },
    NOT {
      EXISTS (`case CG2`) {
        AND {
          (`CG2 has a first child`),
          OR {
            (`CG2's first child contains a child token of type PATTERN_VARIABLE_DEF`),
            (`CG2's first child contains a child token of type RECORD_PATTERN_DEF`)
          }
        }
      }
    },
    NOT {
      EXISTS (`case CG3`) {
        AND {
          (`CG3 has a first child`),
          EXISTS (`case CG3_parent`) {
            AND {
              (`CG3_parent is the parent of CG3`),
              EXISTS (`case CG4`) {
                AND {
                  (`CG4 contains a child token of type EXPR`),
                  (`CG4's EXPR child contains a child token of type LITERAL_NULL`)
                }
              }
            }
          }
        }
      }
    },
    NOT {
      OR {
        (`SW's parent token type is SLIST`),
        (`SW's parent token type is LITERAL_IF`),
        (`SW's parent token type is LITERAL_ELSE`),
        (`SW's parent token type is LITERAL_DO`),
        (`SW's parent token type is LITERAL_WHILE`),
        (`SW's parent token type is LITERAL_FOR`),
        (`SW's parent token type is LABELED_STAT`)
      }
    }
  }
}

SuperCloneCheck.checker_dsl:
EXISTS (`method MD`) {
  AND {
    (`the name of MD is "clone"`),
    (`MD is not a native method (its modifiers do not contain LITERAL_NATIVE)`),
    (`MD has an empty parameter list`),
    NOT {
      EXISTS (`literal LS`) {
        AND {
          (`LS is a descendant of MD`),
          OR {
            AND {
              (`the token immediately following LS (skipping TYPE_ARGUMENTS if present) is not null`),
              (`the text of that following token is "clone"`)
            },
            AND {
              NOT {
                AND {
                  (`the token immediately following LS (skipping TYPE_ARGUMENTS if present) is not null`),
                  (`the text of that following token is "clone"`)
                }
              },
              (`the parent AST node of LS is not a METHOD_REF`),
              (`the parent AST node of LS has no arguments (the sibling arguments list node has no children)`),
              EXISTS (`method AMD`) {
                AND {
                  (`AMD is an ancestor of the parent node of LS`),
                  (`AMD is the same node as MD`)
                }
              }
            }
          }
        }
      }
    }
  }
}

EqualsHashCodeCheck.checker_dsl:
OR {
  EXISTS (`method M1`) {
    AND {
      (`M1 is defined inside a class/interface/enum body OBJ`),
      (`M1's method name is "equals"`),
      (`M1 has exactly one parameter`),
      (`the single parameter's type is exactly "Object" or "java.lang.Object"`),
      OR {
        (`M1 has a method body (block)`),
        (`M1 is declared with the native modifier`)
      },
      NOT {
        EXISTS (`method M2`) {
          AND {
            (`M2 is defined inside the same class/interface/enum body OBJ`),
            (`M2's method name is "hashCode"`),
            (`M2 has zero parameters`),
            OR {
              (`M2 has a method body (block)`),
              (`M2 is declared with the native modifier`)
            }
          }
        }
      }
    }
  },
  EXISTS (`method M3`) {
    AND {
      (`M3 is defined inside a class/interface/enum body OBJ`),
      (`M3's method name is "hashCode"`),
      (`M3 has zero parameters`),
      OR {
        (`M3 has a method body (block)`),
        (`M3 is declared with the native modifier`)
      },
      NOT {
        EXISTS (`method M4`) {
          AND {
            (`M4 is defined inside the same class/interface/enum body OBJ`),
            (`M4's method name is "equals"`),
            (`M4 has exactly one parameter`),
            (`the single parameter's type is exactly "Object" or "java.lang.Object"`),
            OR {
              (`M4 has a method body (block)`),
              (`M4 is declared with the native modifier`)
            }
          }
        }
      }
    }
  }
}
